body.script:
// Toggle dropdown menu - runs on every page load
(function() {
  // Store references to cleanup old listeners
  let currentBurgerHandler = null;
  let currentOutsideClickHandler = null;
  let currentScrollHandler = null;
  let isInitialized = false;
  let retryCount = 0;
  const MAX_RETRIES = 50; // Try for up to 5 seconds (50 * 100ms)

  function initMenu() {
    // Prevent multiple simultaneous initializations
    if (isInitialized && retryCount === 0) {
      return;
    }

    const floatingNav = document.getElementById('floating-nav');
    const burgerMenu = document.getElementById('burger-menu');
    const dropdownMenu = document.getElementById('dropdown-menu');
    const burgerIcon = document.getElementById('burger-icon');
    const homeIcon = document.getElementById('home-icon');

    if (!burgerMenu || !dropdownMenu || !burgerIcon || !homeIcon) {
      // Retry with exponential backoff
      retryCount++;
      if (retryCount < MAX_RETRIES) {
        const delay = Math.min(100 * retryCount, 500); // Max 500ms delay
        setTimeout(initMenu, delay);
      }
      return;
    }

    // Reset retry count on success
    retryCount = 0;

    // Ensure menu is closed on page load
    dropdownMenu.classList.remove('open');
    burgerIcon.classList.remove('hidden');
    homeIcon.classList.add('hidden');
    burgerMenu.setAttribute('aria-expanded', 'false');

    // Remove old event listeners if they exist
    if (currentBurgerHandler && burgerMenu) {
      burgerMenu.removeEventListener('click', currentBurgerHandler);
    }
    if (currentOutsideClickHandler) {
      document.removeEventListener('click', currentOutsideClickHandler, true);
    }
    if (currentScrollHandler) {
      window.removeEventListener('scroll', currentScrollHandler, { passive: true });
    }

    // Remove old link handler if it exists
    if (dropdownMenu._linkClickHandler) {
      dropdownMenu.removeEventListener('click', dropdownMenu._linkClickHandler);
    }

    // Create new click handler
    currentBurgerHandler = function(e) {
      e.preventDefault();
      e.stopPropagation();
      const isOpen = dropdownMenu.classList.contains('open');

      if (isOpen) {
        // Navigate to home when home icon is clicked
        window.location.href = '/';
      } else {
        // Open menu and show home icon
        dropdownMenu.classList.add('open');
        burgerIcon.classList.add('hidden');
        homeIcon.classList.remove('hidden');
        burgerMenu.setAttribute('aria-expanded', 'true');
      }
    };

    // Attach new click handler
    burgerMenu.addEventListener('click', currentBurgerHandler);

    // Close menu when clicking outside
    currentOutsideClickHandler = function(e) {
      if (dropdownMenu.classList.contains('open') && 
          !dropdownMenu.contains(e.target) && 
          !burgerMenu.contains(e.target)) {
        dropdownMenu.classList.remove('open');
        burgerIcon.classList.remove('hidden');
        homeIcon.classList.add('hidden');
        burgerMenu.setAttribute('aria-expanded', 'false');
      }
    };

    document.addEventListener('click', currentOutsideClickHandler, true);

    // Close menu when clicking a link (using event delegation)
    dropdownMenu._linkClickHandler = function(e) {
      // Check if click was on a link
      const link = e.target.closest('a');
      if (link && dropdownMenu.contains(link)) {
        dropdownMenu.classList.remove('open');
        burgerIcon.classList.remove('hidden');
        homeIcon.classList.add('hidden');
        burgerMenu.setAttribute('aria-expanded', 'false');
      }
    };

    // Attach using event delegation
    dropdownMenu.addEventListener('click', dropdownMenu._linkClickHandler);

    // Add scroll effect to floating nav
    currentScrollHandler = function() {
      const currentScrollY = window.scrollY;

      if (currentScrollY > 20) {
        floatingNav?.classList.add('scrolled');
      } else {
        floatingNav?.classList.remove('scrolled');
      }
    };

    window.addEventListener('scroll', currentScrollHandler, { passive: true });
    currentScrollHandler(); // Check initial state

    isInitialized = true;
  }

  // Use MutationObserver to detect when elements are added to DOM
  function observeForElements() {
    const observer = new MutationObserver(function(mutations, obs) {
      const burgerMenu = document.getElementById('burger-menu');
      const dropdownMenu = document.getElementById('dropdown-menu');
      const burgerIcon = document.getElementById('burger-icon');
      const homeIcon = document.getElementById('home-icon');

      if (burgerMenu && dropdownMenu && burgerIcon && homeIcon) {
        obs.disconnect();
        initMenu();
      }
    });

    // Start observing
    if (document.body) {
      observer.observe(document.body, {
        childList: true,
        subtree: true
      });
    }

    // Stop observing after 5 seconds
    setTimeout(function() {
      observer.disconnect();
    }, 5000);
  }

  // Run initialization with multiple strategies
  function runInit() {
    // Reset initialization flag
    isInitialized = false;
    retryCount = 0;

    // Try immediate initialization
    initMenu();

    // Also use MutationObserver as backup
    observeForElements();
  }

  // Run on page load
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', runInit);
  } else {
    // DOM already loaded, run immediately
    runInit();
  }

  // Also try on window load (ensures everything is ready)
  window.addEventListener('load', function() {
    runInit();
  });

  // Also run when page becomes visible (handles back/forward navigation)
  document.addEventListener('visibilitychange', function() {
    if (!document.hidden) {
      setTimeout(runInit, 100);
    }
  });

  // Run on popstate (back/forward navigation)
  window.addEventListener('popstate', function() {
    setTimeout(runInit, 100);
  });

  // Listen for Astro View Transitions (client-side navigation)
  // This is the key fix - Astro uses view transitions for client-side navigation
  document.addEventListener('astro:page-load', function() {
    setTimeout(runInit, 50);
  });

  // Also listen for astro:after-swap (another view transition event)
  document.addEventListener('astro:after-swap', function() {
    setTimeout(runInit, 50);
  });

  // Also re-initialize after a short delay to catch any late-loading elements
  setTimeout(runInit, 200);
})();
